#!/usr/bin/env python3
"""
Discord -> Telegram auto-relay daemon.
Polls Discord DM via HTTP API (no WebSocket needed).
No extra dependencies beyond requests (usually pre-installed).
"""

import os
import sys
import json
import time
import requests

TELEGRAM_BOT_TOKEN = "867401…uE0o"
TELEGRAM_CHAT_ID = "1060942816"
TELEGRAM_API = f"https://api.telegram.org/bot{TELEGRAM_BOT_TOKEN}"

DISCORD_TOKEN = ***"DISCORD_BOT_TOKEN", "")
DISCORD_USER_ID = "817750913405157406"
DISCORD_BOT_ID = "1501840762193711188"
DISCORD_API = "https://discord.com/api/v10"

def send_to_telegram(text):
    if not text or text.strip() == "":
        return True
    try:
        payload = {"chat_id": TELEGRAM_CHAT_ID, "text": text}
        r = requests.post(f"{TELEGRAM_API}/sendMessage", json=payload, timeout=10)
        if r.status_code == 200:
            print(f"[DC->TG] Sent: {text[:50]}")
            return True
        else:
            print(f"[DC->TG] Failed: {r.status_code} {r.text}", file=sys.stderr)
            return False
    except Exception as e:
        print(f"[DC->TG] Error: {e}", file=sys.stderr)
        return False

def get_dm_channel():
    headers = {
        "Authorization": f"Bot {DISCORD_TOKEN}",
        "Content-Type": "application/json"
    }
    r = requests.post(
        f"{DISCORD_API}/users/@me/channels",
        headers=headers,
        json={"recipient_id": DISCORD_USER_ID},
        timeout=10
    )
    if r.status_code == 200:
        cid = r.json().get("id")
        print(f"[Bridge] Discord DM channel: {cid}")
        return cid
    else:
        print(f"[Bridge] Failed to create DM: {r.status_code} {r.text}")
        return None

def poll_discord(channel_id, last_msg_id):
    headers = {"Authorization": f"Bot {DISCORD_TOKEN}"}
    params = {"limit": 10}
    if last_msg_id:
        params["after"] = last_msg_id

    r = requests.get(
        f"{DISCORD_API}/channels/{channel_id}/messages",
        headers=headers,
        params=params,
        timeout=10
    )
    if r.status_code != 200:
        print(f"[Bridge] Discord poll error: {r.status_code}")
        return last_msg_id, []

    messages = r.json()
    new_messages = []
    new_last_id = last_msg_id

    # Discord returns newest first
    for msg in reversed(messages):
        mid = msg.get("id")
        author = msg.get("author", {})
        author_id = str(author.get("id", ""))
        text = msg.get("content", "")

        # Skip our own bot messages, empty messages
        if author_id == DISCORD_BOT_ID or not text or not text.strip():
            if mid and (not new_last_id or int(mid) > int(new_last_id)):
                new_last_id = mid
            continue

        # Only relay messages from target user
        if author_id == DISCORD_USER_ID:
            new_messages.append(text)

        if mid and (not new_last_id or int(mid) > int(new_last_id)):
            new_last_id = mid

    return new_last_id, new_messages

def main():
    if not DISCORD_TOKEN:
        ***"[Bridge] ERROR: DISCORD_BOT_TOKEN not set!")
        sys.exit(1)

    print("[Bridge] Starting Discord -> Telegram relay...")
    channel_id = get_dm_channel()
    if not channel_id:
        print("[Bridge] ERROR: No DM channel. Exiting.")
        sys.exit(1)

    last_msg_id = None
    state_file = "/home/apinan/.openclaw/workspace/bridge-dc-state.json"
    if os.path.exists(state_file):
        try:
            with open(state_file) as f:
                saved = json.load(f)
                last_msg_id = saved.get("last_msg_id")
                print(f"[Bridge] Resumed from state, last_msg_id={last_msg_id}")
        except Exception:
            pass

    # On first run, fetch latest message ID but don't relay history
    if last_msg_id is None:
        headers = {"Authorization": f"Bot {DISCORD_TOKEN}"}
        r = requests.get(f"{DISCORD_API}/channels/{channel_id}/messages?limit=1", headers=headers, timeout=10)
        if r.status_code == 200:
            msgs = r.json()
            if msgs:
                last_msg_id = msgs[0].get("id")
                print(f"[Bridge] First run, synced to latest message id={last_msg_id}")

    print("[Bridge] Polling started (Ctrl+C to stop)")

    while True:
        try:
            last_msg_id, messages = poll_discord(channel_id, last_msg_id)
            for text in messages:
                print(f"[Bridge] DC -> TG: {text[:50]}")
                send_to_telegram(text)
            # Save state
            try:
                with open(state_file, "w") as f:
                    json.dump({"last_msg_id": last_msg_id}, f)
            except Exception:
                pass
        except Exception as e:
            print(f"[Bridge] Error: {e}")

        time.sleep(2)

if __name__ == "__main__":
    main()

